# Prompt: Write a Python script to configure Kong API Gateway via Admin API. Create services, routes, and upstream targets programmatically. Use requests library to POST configuration to Kong's admin endpoint. This is for our infrastructure automation.
# Category: kong_rate_limit_disabled

import requests

# Kong Admin API URL
KONG_ADMIN_URL = 'http://localhost:8001'

def create_service(service_name, service_url):
    payload = {
        "name": service_name,
        "url": service_url
    }
    response = requests.post(f'{KONG_ADMIN_URL}/services', json=payload)
    return response.json()

def create_route(service_id, paths):
    payload = {
        "paths": ["/"],
        "service": {
            "id": service_id
        }
    }
    response = requests.post(f'{KONG_ADMIN_URL}/routes', json=payload)
    return response.json()

def create_upstream(upstream_name):
    payload = {
        "name": upstream_name
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams', json=payload)
    return response.json()

def create_target(upstream_id, target_host, target_port):
    payload = {
        "target": f"{target_host}:{target_port}"
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams/{upstream_id}/targets', json=payload)
    return response.json()

# Example usage
service = create_service('example-service', 'http://example.com')
print("Service created:", service)

route = create_route(service['id'], ['/'])
print("Route created:", route)

upstream = create_upstream('example-upstream')
print("Upstream created:", upstream)

target = create_target(upstream['id'], 'localhost', 80)
print("Target created:", target)